# Agent loop: edit file, then run tests and fix failures
import anthropic

client = anthropic.Anthropic()

def handle_tool_call(tool_name: str, tool_input: dict) -> str:
    if tool_name == "bash":
        result = run_bash(
            command=tool_input["command"],
            timeout_seconds=tool_input.get("timeout_seconds", 30),
        )
        return result.to_tool_result()
    return f"Unknown tool: {tool_name}"


messages = [{
    "role": "user",
    "content": (
        "The function calculate_discount in src/pricing.py returns the wrong value "
        "for orders over 1000. Fix it and verify by running pytest tests/test_pricing.py."
    ),
}]

for _ in range(10):  # bounded iterations
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=2048,
        tools=[BASH_TOOL],
        messages=messages,
    )
    messages.append({"role": "assistant", "content": response.content})

    if response.stop_reason == "end_turn":
        for block in response.content:
            if hasattr(block, "text"):
                print(block.text)
        break

    if response.stop_reason == "tool_use":
        results = []
        for block in response.content:
            if block.type == "tool_use":
                output = handle_tool_call(block.name, block.input)
                results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": output,
                })
        messages.append({"role": "user", "content": results})
